declare const require: any;
declare const process: any;
const fs = require('node:fs');
const { CsvParser, CsvFilter } = require('./csv');

export {}

function help() {
  console.log(`# CSV Processor
This is a simple CSV processor written in TypeScript using Node.js built-in modules.

## Features
- Parse CSV files with support for quoted fields.
- Filter, select, sort, and count rows.
- CLI interface for parsing and statistics.

## Usage
### Parsing CSV

cd dist
node cli.js parse --input <file>

### Statistics

cd dist
node cli.js stats --input <file>

### Help

cd dist
node cli.js --help`);
}

function parseFile(filePath: string) {
  const fileContent = fs.readFileSync(filePath, 'utf-8');
  const parser = new CsvParser();
  return parser.parse(fileContent);
}

function stats(filePath: string) {
  const data = parseFile(filePath);
  const filter = new CsvFilter(data);
  console.log(`Total rows: ${filter.count()}`);
}

if (process.argv.length < 3) {
  help();
} else {
  const command = process.argv[2];
  if (command === '--help') {
    help();
  } else if (command === 'parse' && process.argv.includes('--input')) {
    const filePath = process.argv[process.argv.indexOf('--input') + 1];
    const data = parseFile(filePath);
    console.log(JSON.stringify(data, null, 2));
  } else if (command === 'stats' && process.argv.includes('--input')) {
    const filePath = process.argv[process.argv.indexOf('--input') + 1];
    stats(filePath);
  } else {
    help();
  }
}

